10	} from "recharts";
11	
12	// ── Sample data ──────────────────────────────────────────────
13	// 성격이 뚜렷이 다른 기종들을 연식별로 구성.
14	// 실제 서비스에서는 이 부분이 별도 데이터 파일/DB로 분리됩니다.
15	const BIKES = [
16	  {
17	    id: "grom-2022",
18	    maker: "Honda",
19	    model: "GROM",
20	    year: 2022,
21	    category: "미니/입문",
22	    displacement: 124,
23	    power: 9.7,
24	    torque: 10.8,
