31	  },
32	  {
33	    id: "grom-2017",
34	    maker: "Honda",
35	    model: "GROM",
36	    year: 2017,
37	    category: "미니/입문",
38	    displacement: 125,
39	    power: 9.6,
40	    torque: 11.0,
41	    weight: 104,
42	    seatHeight: 760,
43	    fuelEconomy: 60,
44	    tankCapacity: 5.5,
45	    topSpeed: 88,
46	    priceUsedKRW: 2500000,
47	  },
48	  {
49	    id: "mt03-2023",
50	    maker: "Yamaha",
51	    model: "MT-03",
52	    year: 2023,
53	    category: "네이키드",
54	    displacement: 321,
55	    power: 42,
56	    torque: 29.6,
57	    weight: 168,
58	    seatHeight: 780,
59	    fuelEconomy: 30,
60	    tankCapacity: 14.0,
61	    topSpeed: 180,
62	    priceUsedKRW: 5200000,
63	  },
64	  {
65	    id: "z900-2021",
66	    maker: "Kawasaki",
67	    model: "Z900",
68	    year: 2021,
69	    category: "네이키드",
70	    displacement: 948,
71	    power: 125,
72	    torque: 98.6,
73	    weight: 212,
74	    seatHeight: 820,
75	    fuelEconomy: 18,
76	    tankCapacity: 17.0,
77	    topSpeed: 240,
78	    priceUsedKRW: 9800000,
79	  },
80	  {
81	    id: "r1250gs-2022",
82	    maker: "BMW",
83	    model: "R1250GS",
84	    year: 2022,
85	    category: "어드벤처",
86	    displacement: 1254,
87	    power: 136,
88	    torque: 143,
89	    weight: 249,
90	    seatHeight: 850,
91	    fuelEconomy: 20,
92	    tankCapacity: 20.0,
93	    topSpeed: 220,
94	    priceUsedKRW: 19500000,
95	  },
96	  {
97	    id: "goldwing-2021",
98	    maker: "Honda",
99	    model: "Gold Wing",
100	    year: 2021,
101	    category: "투어러",
102	    displacement: 1833,
103	    power: 126,
104	    torque: 170,
105	    weight: 365,
106	    seatHeight: 745,
107	    fuelEconomy: 16,
108	    tankCapacity: 21.1,
109	    topSpeed: 200,
110	    priceUsedKRW: 28000000,
111	  },
112	  {
113	    id: "pcx125-2023",
114	    maker: "Honda",
115	    model: "PCX 125",
116	    year: 2023,
117	    category: "스쿠터",
118	    displacement: 125,
119	    power: 12.3,
120	    torque: 11.8,
121	    weight: 132,
122	    seatHeight: 764,
123	    fuelEconomy: 48,
124	    tankCapacity: 8.1,
125	    topSpeed: 105,
126	    priceUsedKRW: 2900000,
127	  },
128	  {
129	    id: "harley-iron883-2020",
130	    maker: "Harley-Davidson",
131	    model: "Iron 883",
132	    year: 2020,
133	    category: "크루저",
134	    displacement: 883,
135	    power: 50,
136	    torque: 70,
137	    weight: 256,
138	    seatHeight: 760,
139	    fuelEconomy: 22,
140	    tankCapacity: 12.5,
141	    topSpeed: 170,
142	    priceUsedKRW: 9500000,
143	  },
144	];
145	
146	// 비교 항목 정의: 단위와 "높을수록 좋은지" 여부
147	const SPECS = [
148	  { key: "displacement", label: "배기량", unit: "cc", higherBetter: null },
149	  { key: "power", label: "최고출력", unit: "hp", higherBetter: true },
150	  { key: "torque", label: "토크", unit: "Nm", higherBetter: true },
151	  { key: "weight", label: "공차중량", unit: "kg", higherBetter: false },
152	  { key: "seatHeight", label: "시트고", unit: "mm", higherBetter: null },
153	  { key: "fuelEconomy", label: "연비", unit: "km/L", higherBetter: true },
154	  { key: "tankCapacity", label: "연료탱크", unit: "L", higherBetter: true },
155	  { key: "topSpeed", label: "최고속도", unit: "km/h", higherBetter: true },
156	  { key: "priceUsedKRW", label: "중고시세", unit: "만원", higherBetter: false },
157	];
158	
159	// 레이더 차트에 쓸 항목 (0~100 정규화)
160	const RADAR_SPECS = ["power", "torque", "fuelEconomy", "topSpeed", "weight"];
161	
162	const SERIES_COLORS = ["#FF5C00", "#1FB6A6", "#7C5CFF"];
163	
164	function fmt(spec, value) {
165	  if (spec.key === "priceUsedKRW") return Math.round(value / 10000).toLocaleString();
166	  return value.toLocaleString();
167	}
168	
169	export default function App() {
170	  const [selected, setSelected] = useState(["mt03-2023", "z900-2021"]);
171	  const [pickerOpen, setPickerOpen] = useState(false);
172	
173	  const selectedBikes = useMemo(
174	    () => selected.map((id) => BIKES.find((b) => b.id === id)).filter(Boolean),
175	    [selected]
176	  );
177	
178	  function toggleBike(id) {
179	    setSelected((prev) => {
180	      if (prev.includes(id)) return prev.filter((x) => x !== id);
181	      if (prev.length >= 3) return prev; // 최대 3대 비교
182	      return [...prev, id];
183	    });
184	  }
185	
186	  // 각 항목별 최고/최저 (하이라이트용)
187	  const extremes = useMemo(() => {
188	    const out = {};
189	    for (const spec of SPECS) {
190	      const vals = selectedBikes.map((b) => b[spec.key]);
191	      out[spec.key] = { max: Math.max(...vals), min: Math.min(...vals) };
192	    }
193	    return out;
194	  }, [selectedBikes]);
195	
196	  // 레이더 데이터: 전체 데이터 기준으로 0~100 정규화
197	  const radarData = useMemo(() => {
198	    return RADAR_SPECS.map((key) => {
199	      const spec = SPECS.find((s) => s.key === key);
200	      const all = BIKES.map((b) => b[key]);
201	      const min = Math.min(...all);
202	      const max = Math.max(...all);
203	      const norm = (v) => {
204	        const t = max === min ? 0.5 : (v - min) / (max - min);
205	        // 낮을수록 좋은 항목(무게)은 뒤집어서 표시
206	        return Math.round((spec.higherBetter === false ? 1 - t : t) * 100);
207	      };
208	      const row = { spec: spec.label };
209	      selectedBikes.forEach((b, i) => {
210	        row[`bike${i}`] = norm(b[key]);
211	      });
212	      return row;
213	    });
214	  }, [selectedBikes]);
215	
216	  return (
217	    <div className="moto-root">
218	      <style>{css}</style>
219	
220	      <header className="moto-header">
221	        <div className="eyebrow">제원 비교 · PROTOTYPE</div>
222	        <h1>
223	          어떤 <span className="hl">바이크</span>가
224	          <br />당신에게 맞을까
225	        </h1>
226	        <p className="sub">
227	          최대 3대까지 나란히 놓고, 숫자와 균형을 한눈에 비교합니다.
228	        </p>
229	      </header>
230	
231	      {/* 선택된 바이크 칩 */}
232	      <div className="chips">
233	        {selectedBikes.map((b, i) => (
234	          <div className="chip" key={b.id} style={{ "--c": SERIES_COLORS[i] }}>
235	            <span className="chip-dot" />
236	            <span className="chip-name">
237	              {b.maker} {b.model}
238	              <em>'{String(b.year).slice(2)}</em>
239	            </span>
240	            <button className="chip-x" onClick={() => toggleBike(b.id)} aria-label="제거">
241	              ×
242	            </button>
243	          </div>
244	        ))}
245	        {selectedBikes.length < 3 && (
246	          <button className="chip chip-add" onClick={() => setPickerOpen((o) => !o)}>
247	            + 기종 추가
248	          </button>
249	        )}
250	      </div>
251	
252	      {/* 기종 선택 패널 */}
253	      {pickerOpen && (
254	        <div className="picker">
255	          {BIKES.map((b) => {
256	            const isOn = selected.includes(b.id);
257	            const disabled = !isOn && selected.length >= 3;
258	            return (
259	              <button
260	                key={b.id}
261	                className={`picker-item ${isOn ? "on" : ""} ${disabled ? "off" : ""}`}
262	                onClick={() => !disabled && toggleBike(b.id)}
263	              >
264	                <span className="pi-cat">{b.category}</span>
265	                <span className="pi-name">
266	                  {b.maker} {b.model}
267	                </span>
268	                <span className="pi-year">{b.year} · {b.displacement}cc</span>
269	              </button>
270	            );
271	          })}
272	        </div>
273	      )}
274	
275	      {selectedBikes.length === 0 ? (
276	        <div className="empty">비교할 기종을 추가해 주세요.</div>
277	      ) : (
278	        <>
279	          {/* 레이더 차트 */}
280	          <section className="panel">
281	            <div className="panel-label">성능 균형</div>
282	            <div className="radar-wrap">
283	              <ResponsiveContainer width="100%" height={340}>
284	                <RadarChart data={radarData} outerRadius="72%">
285	                  <PolarGrid stroke="#2a2a2e" />
286	                  <PolarAngleAxis
287	                    dataKey="spec"
288	                    tick={{ fill: "#9a9aa0", fontSize: 12 }}
289	                  />
290	                  <PolarRadiusAxis domain={[0, 100]} tick={false} axisLine={false} />
291	                  {selectedBikes.map((b, i) => (
292	                    <Radar
293	                      key={b.id}
294	                      name={`${b.model} '${String(b.year).slice(2)}`}
295	                      dataKey={`bike${i}`}
296	                      stroke={SERIES_COLORS[i]}
297	                      fill={SERIES_COLORS[i]}
298	                      fillOpacity={0.18}
299	                      strokeWidth={2}
300	                    />
301	                  ))}
302	                  <Legend wrapperStyle={{ fontSize: 12 }} />
303	                </RadarChart>
304	              </ResponsiveContainer>
305	            </div>
306	            <div className="radar-note">
307	              전체 데이터 기준 상대 점수(0~100). 무게는 가벼울수록 높은 점수.
308	            </div>
309	          </section>
310	
311	          {/* 제원 표 */}
312	          <section className="panel">
313	            <div className="panel-label">제원 비교</div>
314	            <div className="table-scroll">
315	              <table className="spec-table">
316	                <thead>
317	                  <tr>
318	                    <th className="th-spec">항목</th>
319	                    {selectedBikes.map((b, i) => (
320	                      <th key={b.id} style={{ "--c": SERIES_COLORS[i] }}>
321	                        <span className="th-model">{b.model}</span>
322	                        <span className="th-year">'{String(b.year).slice(2)}</span>
323	                      </th>
324	                    ))}
325	                  </tr>
326	                </thead>
327	                <tbody>
328	                  {SPECS.map((spec) => (
329	                    <tr key={spec.key}>
330	                      <td className="td-spec">
331	                        {spec.label}
332	                        <span className="td-unit">{spec.unit}</span>
333	                      </td>
334	                      {selectedBikes.map((b) => {
335	                        const v = b[spec.key];
336	                        const ext = extremes[spec.key];
337	                        let cls = "";
338	                        if (spec.higherBetter !== null && ext.max !== ext.min) {
339	                          const isBest =
340	                            spec.higherBetter ? v === ext.max : v === ext.min;
341	                          const isWorst =
342	                            spec.higherBetter ? v === ext.min : v === ext.max;
343	                          if (isBest) cls = "best";
344	                          else if (isWorst) cls = "worst";
345	                        }
346	                        return (
347	                          <td key={b.id} className={`td-val ${cls}`}>
348	                            {fmt(spec, v)}
349	                            {cls === "best" && <span className="badge">▲</span>}
350	                          </td>
351	                        );
352	                      })}
353	                    </tr>
354	                  ))}
355	                </tbody>
356	              </table>
357	            </div>
358	            <div className="legend-row">
359	              <span className="lg best">▲ 항목별 우위</span>
360	              <span className="lg worst">상대적 열위</span>
361	            </div>
362	          </section>
363	        </>
364	      )}
365	
366	      <footer className="moto-foot">
367	        프로토타입 · 데이터는 예시이며 실제 제원과 다를 수 있습니다
368	      </footer>
369	    </div>
370	  );
371	}
372	
373	const css = `
374	.moto-root {
375	  --bg: #121214;
376	  --panel: #1a1a1e;
377	  --line: #2a2a2e;
378	  --text: #ececf0;
379	  --muted: #9a9aa0;
380	  --orange: #FF5C00;
381	  font-family: "Inter", -apple-system, BlinkMacSystemFont, "Apple SD Gothic Neo", "Pretendard", sans-serif;
382	  background: var(--bg);
383	  color: var(--text);
384	  min-height: 100%;
385	  max-width: 820px;
386	  margin: 0 auto;
387	  padding: 28px 20px 60px;
388	  -webkit-font-smoothing: antialiased;
389	}
390	.moto-header { margin-bottom: 22px; }
391	.eyebrow {
392	  font-size: 11px; letter-spacing: 0.22em; font-weight: 700;
393	  color: var(--orange); text-transform: uppercase; margin-bottom: 14px;
394	}
395	.moto-header h1 {
396	  font-size: clamp(30px, 7vw, 46px); line-height: 1.04; font-weight: 800;
397	  letter-spacing: -0.02em; margin: 0 0 12px;
398	}
399	.moto-header h1 .hl { color: var(--orange); }
400	.sub { color: var(--muted); font-size: 15px; margin: 0; }
401	
402	.chips { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 14px; }
403	.chip {
404	  display: inline-flex; align-items: center; gap: 8px;
405	  background: var(--panel); border: 1px solid var(--line);
406	  border-radius: 999px; padding: 7px 8px 7px 13px;
407	  font-size: 13px; font-weight: 600;
408	}
409	.chip-dot { width: 9px; height: 9px; border-radius: 50%; background: var(--c); }
410	.chip-name em { font-style: normal; color: var(--muted); margin-left: 3px; font-weight: 500; }
411	.chip-x {
412	  border: none; background: transparent; color: var(--muted);
413	  font-size: 18px; line-height: 1; cursor: pointer; padding: 0 4px;
414	}
415	.chip-x:hover { color: var(--text); }
416	.chip-add {
417	  cursor: pointer; color: var(--orange); border-style: dashed;
418	  border-color: var(--orange); padding: 7px 14px;
419	}
420	.chip-add:hover { background: rgba(255,92,0,0.08); }
421	
422	.picker {
423	  display: grid; grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
424	  gap: 8px; margin-bottom: 18px;
425	}
426	.picker-item {
427	  text-align: left; background: var(--panel); border: 1px solid var(--line);
428	  border-radius: 12px; padding: 12px; cursor: pointer; display: flex;
429	  flex-direction: column; gap: 3px; transition: border-color .15s, background .15s;
430	}
431	.picker-item:hover { border-color: #444; }
432	.picker-item.on { border-color: var(--orange); background: rgba(255,92,0,0.07); }
433	.picker-item.off { opacity: 0.35; cursor: not-allowed; }
434	.pi-cat { font-size: 10px; letter-spacing: 0.1em; color: var(--orange); font-weight: 700; text-transform: uppercase; }
435	.pi-name { font-size: 14px; font-weight: 700; }
436	.pi-year { font-size: 12px; color: var(--muted); }
437	
438	.empty {
439	  text-align: center; color: var(--muted); padding: 60px 0;
440	  border: 1px dashed var(--line); border-radius: 16px;
441	}
442	
443	.panel {
444	  background: var(--panel); border: 1px solid var(--line);
445	  border-radius: 18px; padding: 18px 18px 20px; margin-bottom: 16px;
446	}
447	.panel-label {
448	  font-size: 12px; letter-spacing: 0.14em; text-transform: uppercase;
449	  color: var(--muted); font-weight: 700; margin-bottom: 8px;
450	}
451	.radar-wrap { margin: 0 -8px; }
452	.radar-note { font-size: 11px; color: var(--muted); margin-top: 6px; text-align: center; }
453	
454	.table-scroll { overflow-x: auto; margin: 0 -4px; }
455	.spec-table { width: 100%; border-collapse: collapse; font-size: 14px; }
456	.spec-table th, .spec-table td {
457	  padding: 11px 10px; text-align: right; border-bottom: 1px solid var(--line);
458	  white-space: nowrap;
459	}
460	.th-spec, .td-spec { text-align: left; }
461	.spec-table thead th { vertical-align: bottom; }
462	.th-model { display: block; font-weight: 800; font-size: 15px; color: var(--c); }
463	.th-year { display: block; font-size: 11px; color: var(--muted); font-weight: 500; }
464	.td-spec { color: var(--muted); font-weight: 600; }
465	.td-unit { display: block; font-size: 11px; color: #66666c; font-weight: 400; }
466	.td-val { font-variant-numeric: tabular-nums; font-weight: 600; }
467	.td-val.best { color: var(--orange); font-weight: 800; }
468	.td-val.worst { color: #66666c; }
469	.badge { font-size: 9px; margin-left: 4px; vertical-align: middle; }
470	
471	.legend-row { display: flex; gap: 16px; margin-top: 12px; font-size: 11px; }
472	.lg { color: var(--muted); }
473	.lg.best { color: var(--orange); }
474	
475	.moto-foot {
476	  text-align: center; color: #55555a; font-size: 11px; margin-top: 24px;
477	}
478	`;
